57	type RunState = "idle" | "running" | "done" | "error";
58	
59	interface CodeBlockState {
60		output: string;
61		state: RunState;
62	}
63	
64	/** Run JavaScript in a (lightly) sandboxed way by capturing console.log. */
65	async function runJs(code: string): Promise<string> {
66		const logs: string[] = [];
67		const originalLog = console.log;
68		const originalError = console.error;
69		const originalWarn = console.warn;
70	
71		console.log = (...args: unknown[]) =>
72			logs.push(args.map((a) => (typeof a === "object" ? JSON.stringify(a, null, 2) : String(a))).join(" "));
73		console.error = (...args: unknown[]) =>
74			logs.push(`[error] ${args.map((a) => String(a)).join(" ")}`);
75		console.warn = (...args: unknown[]) =>
76			logs.push(`[warn] ${args.map((a) => String(a)).join(" ")}`);
77	
78		try {
79			const fn = new Function(code);
80			const result = await fn();
81			if (result !== undefined) {
82				logs.push(
83					`↳ ${typeof result === "object" ? JSON.stringify(result, null, 2) : String(result)}`,
84				);
85			}
86		} catch (err) {
87			console.error = originalError;
88			console.log = originalLog;
89			console.warn = originalWarn;
90			throw err;
91		} finally {
92			console.error = originalError;
93			console.log = originalLog;
94			console.warn = originalWarn;
95		}
96	
97		return logs.join("\n") || "✅ Executed successfully (no output)";
98	}
99	
100	/** Run Python via Pyodide loaded from CDN on demand. */
101	async function runPython(code: string): Promise<string> {
102		const cdnUrl = "https://cdn.jsdelivr.net/pyodide/v0.27.2/full/pyodide.mjs";
103		// @ts-ignore — dynamic CDN import, no types available
104		const { loadPyodide } = await import(/* @vite-ignore */ cdnUrl);
105		const pyodide = await loadPyodide();
106	
107		const lines: string[] = [];
108		pyodide.setStdout({ batched: (text: string) => lines.push(text) });
109		pyodide.setStderr({ batched: (text: string) => lines.push(`[stderr] ${text}`) });
110	
111		await pyodide.runPythonAsync(code);
112		return lines.join("\n") || "✅ Executed successfully (no output)";
113	}
