115	function CodeBlock({ lang, children }: { lang: string; children: string }) {
116		const [{ output, state }, setRun] = useState<CodeBlockState>({
117			output: "",
118			state: "idle",
119		});
120		const [copied, setCopied] = useState(false);
121	
122		const isExecutable = EXECUTABLE_LANGS.has(lang);
123		const displayLang = lang || "text";
124	
125		const copyCode = useCallback(async () => {
