	language,
}: {
	code: string;
	language: string;
}) {
	return (
		<SyntaxHighlighter
			language={language}
			style={vscDarkPlus}
			showLineNumbers
			lineNumberStyle={{ minWidth: "2.2em", paddingRight: "1em", color: "#6e7681", fontSize: "0.75em" }}
			customStyle={{
				margin: 0,
				borderRadius: 0,
				fontSize: "0.82rem",
				lineHeight: 1.55,
				background: "#0d1117",
			}}
		>
			{code.replace(/\n$/, "")}
		</SyntaxHighlighter>
	);
}

